mxGraph.add:
function(cell)
{
	var esc = function(s) {
		return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
	};
	var tag = cell.value ? cell.value.tagName : '';
	var label = cell.getAttribute('label') || '';
	var info = '';

	if (tag === 'Transition') {
		// Surface the routing decision on hover — the when condition
		// IS the logic; nobody should have to click every edge to
		// read the flow.
		var when = cell.getAttribute('when') || '';
		var seq = cell.getAttribute('seq') || '';
		var txId = cell.getAttribute('txId') || '';
		var subscriber = cell.getAttribute('subscriber') || '';
		var region = cell.getAttribute('region') || '';
		var modifier = cell.getAttribute('routeModifier') || '';
		info += '<br>when: ' + (when ? esc(when) : '(always)');
		if (seq) info += '<br>order: ' + esc(seq) + ' (first match wins)';
		if (txId) info += '<br>id: ' + esc(txId);
		if (subscriber) info += '<br>subscriber: ' + esc(subscriber);
		if (region) info += '<br>region: ' + esc(region);
		if (cell.value && cell.value.childNodes) {
			for (var i = 0; i < cell.value.childNodes.length; i++) {
				var c = cell.value.childNodes[i];
				if (c.nodeType === 1 && c.nodeName === 'route') {
					info += '<br>route: ' + esc(c.getAttribute('uri') || '');
				}
			}
		}
		if (modifier) info += '<br>modifier: ' + esc(modifier);
		return '<b>' + esc(tag) + ': ' + esc(label) + '</b>' + info;
	}

	// Egress exit node (Gateway with role="egress"): where the call
	// leaves OCCAS. The kind is inferred from topology — an out-edge back
	// to a state makes it ROUTE_BACK (resume there on return), else
	// ROUTE_FINAL.
	if (cell.getAttribute('role') === 'egress') {
		var egReturn = null;
		var egEdges = cell.edges || [];
		for (var ei = 0; ei < egEdges.length; ei++) {
			var ee = egEdges[ei];
			if (ee.source === cell &amp;&amp; ee.target &amp;&amp; ee.target.value
					&amp;&amp; ee.target.getAttribute('role') !== 'egress') {
				egReturn = ee.target.getAttribute('stateId') || ee.target.getAttribute('label');
				break;
			}
		}
		info += '<br>egress exit (the call leaves OCCAS here)';
		if (cell.value &amp;&amp; cell.value.childNodes) {
			for (var k = 0; k < cell.value.childNodes.length; k++) {
				var rc = cell.value.childNodes[k];
				if (rc.nodeType === 1 &amp;&amp; rc.nodeName === 'route') {
					info += '<br>route: ' + esc(rc.getAttribute('uri') || '');
				}
			}
		}
		info += egReturn
				? '<br>ROUTE_BACK &#8594; resumes at ' + esc(egReturn)
				: '<br>ROUTE_FINAL (leaves for good)';
		return '<b>Egress: ' + esc(label) + '</b>' + info;
	}

	if (tag === 'State' || tag === 'Gateway' || tag === 'Ingress') {
		// Selector summary: which variables this state publishes.
		var sels = [];
		if (cell.value && cell.value.childNodes) {
			for (var j = 0; j < cell.value.childNodes.length; j++) {
				var s = cell.value.childNodes[j];
				if (s.nodeType === 1 && s.nodeName === 'selector') {
					sels.push(esc(s.getAttribute('id') || '(no id)')
							+ ' (' + esc(s.getAttribute('type') || 'attribute') + ')');
				}
			}
		}
		if (sels.length > 0) {
			info += '<br>selectors: ' + sels.join(', ');
		} else if (tag === 'State') {
			info += '<br>selectors: none';
		}
		if (tag === 'Gateway' || tag === 'Ingress') {
			var match = cell.getAttribute('match');
			if (match) {
				info += '<br>ingress entry state; source match: ' + esc(match);
			} else {
				info += '<br>default ingress (the "null" state — any source)';
			}
		}
		return '<b>' + esc(tag) + ': ' + esc(label) + '</b>' + info +
				'<br>Edges: ' + cell.getEdgeCount();
	}

	return '<b>' + esc(tag) + ': ' + esc(label) + '</b>' + info +
			'<br>Edges: ' + cell.getEdgeCount() +
			'<br>Children: ' + cell.getChildCount();
}

function(cell)
{
	// Transitions get a derived display label: plan-dispatch
	// conditions render as "INVITE · tier=gold" and the
	// unconditional member of a family as "INVITE · default".
	// Stored label attribute stays the bare SIP method. When the
	// Route Simulator's live overlay is on, the hit count is
	// appended ("INVITE · tier=gold · 1284").
	if (cell.value && cell.value.tagName === 'Transition'
			&& window.flowPlans) {
		var label = window.flowPlans.displayLabel(cell);
		if (window.flowSimulate) {
			label = window.flowSimulate.decorate(cell, label);
		}
		return label;
	}
	// A State/ingress whose state id differs from its application name
	// (a second instance of the same app) shows the id as a qualifier so
	// the two boxes read distinctly: "b2bua\n(b2bua-caller)".
	var lbl = cell.getAttribute('label');
	if (cell.value && (cell.value.tagName === 'State' || cell.value.tagName === 'Gateway')
			&& cell.getAttribute('role') !== 'egress') {
		var sid = cell.getAttribute('stateId');
		if (sid && sid.length > 0 && sid !== lbl) {
			return lbl + '\n(' + sid + ')';
		}
	}
	return lbl;
}

function(cell, evt)
{
	// In-place edit must present the bare stored label, not the
	// decorated display string from convertValueToString — otherwise
	// committing an edit would write "INVITE · tier=gold" into the
	// method attribute.
	return cell.getAttribute('label') || '';
}

mxGraphModel.add:
function(cell, value)
{
	var previous = null;

	if (isNaN(value.nodeType))
	{
		previous = cell.getAttribute('label');
		cell.setAttribute('label', value);
	}
	else
	{
		previous = cell.value;
		cell.value = value;
	}

	return previous;
}
